{
  "mode": "method",
  "tests": [
    {
      "name": "textarea_background_color",
      "input": {"browser": "Firefox", "element": "textarea"},
      "output": {"backgroundColor": "white"},
      "notes": "Validates that the textarea background color is set to white in Firefox."
    },
    {
      "name": "textarea_no_unwanted_changes",
      "input": {"browser": "Firefox", "element": "textarea", "existingFunction": true},
      "output": {"functionStatus": "unchanged"},
      "notes": "Ensures that existing functions are not altered during the patch."
    },
    {
      "name": "patch_creation",
      "input": {"base": "latest reskin-or-only", "changes": "textarea background"},
      "output": {"patchStatus": "created"},
      "notes": "Checks if a new patch can be created based on the latest reskin."
    },
    {
      "name": "textarea_style_guidance",
      "input": {"browser": "Firefox", "element": "textarea", "styleGuide": "Figma"},
      "output": {"styleCompliance": true},
      "notes": "Validates that the textarea adheres to the style guidance from Figma."
    },
    {
      "name": "textarea_empty_state",
      "input": {"browser": "Firefox", "element": "textarea", "content": ""},
      "output": {"isEmpty": true},
      "notes": "Tests the textarea's behavior when it is empty."
    },
    {
      "name": "textarea_with_content",
      "input": {"browser": "Firefox", "element": "textarea", "content": "Test content"},
      "output": {"content": "Test content"},
      "notes": "Ensures that the textarea can accept and display content correctly."
    },
    {
      "name": "textarea_edge_case_large_input",
      "input": {"browser": "Firefox", "element": "textarea", "content": "A".repeat(10000)},
      "output": {"contentLength": 10000},
      "notes": "Tests the textarea's handling of a very large input."
    },
    {
      "name": "textarea_edge_case_special_characters",
      "input": {"browser": "Firefox", "element": "textarea", "content": "!@#$%^&*()"},
      "output": {"content": "!@#$%^&*()"},
      "notes": "Validates that the textarea can handle special characters."
    }
  ],
  "assumptions": "The textarea is the only element being modified in the patch.",
  "notes": "Ensure to test in the latest version of Firefox."
}
